mapper.select:
SELECT tm.trip_member_id AS tripMemberId, tm.trip_id AS tripId, tm.user_id AS userId, au.nickname AS nickname, tm.member_role AS memberRole, tm.invite_status AS inviteStatus, tm.joined_at AS joinedAt FROM TRIP_MEMBER tm JOIN APP_USER au ON tm.user_id = au.user_id WHERE tm.trip_id IN
#{tripId}
ORDER BY tm.trip_id ASC, CASE tm.member_role WHEN 'OWNER' THEN 0 ELSE 1 END, tm.joined_at ASC, tm.trip_member_id ASC

SELECT EXISTS (
    SELECT 1
    FROM TRIP t
    LEFT JOIN TRIP_MEMBER tm
      ON tm.trip_id = t.trip_id
     AND tm.user_id = #{userId}
     AND tm.invite_status = 'ACCEPTED'
    WHERE t.trip_id = #{tripId}
      AND (t.owner_user_id = #{userId} OR tm.trip_member_id IS NOT NULL)
)

mapper.update:
UPDATE TRIP
SET title = #{title},
    description = #{description},
    trip_type = #{tripType},
    start_date = #{startDate},
    end_date = #{endDate}
WHERE trip_id = #{tripId}
  AND owner_user_id = #{userId}

mapper.delete:
DELETE FROM TRIP
WHERE trip_id = #{tripId}
  AND owner_user_id = #{userId}

DELETE FROM TRIP_MEMBER
WHERE trip_id = #{tripId}
  AND user_id = #{userId}

mapper.update:
UPDATE TRIP_MEMBER
SET member_role = #{memberRole}
WHERE trip_id = #{tripId}
  AND user_id = #{userId}
